#!/usr/bin/env python3
import os
import re
from pathlib import Path

# Find all imports of collections ABCs
patterns = {
    'from_collections_abc': re.compile(r'from\s+collections\.abc\s+import'),
    'from_shim': re.compile(r'from\s+ansible\.module_utils\.common\._collections_compat\s+import'),
    'import_shim': re.compile(r'import\s+ansible\.module_utils\.common\._collections_compat'),
}

lib_path = Path('/workspace/lib/ansible')
test_path = Path('/workspace/test')

results = {
    'files_with_collections_abc': [],
    'files_with_shim': [],
    'total_collections_abc_imports': 0,
    'total_shim_imports': 0,
}

for py_file in list(lib_path.rglob('*.py')) + list(test_path.rglob('*.py')):
    try:
        content = py_file.read_text(encoding='utf-8')

        if patterns['from_collections_abc'].search(content):
            results['files_with_collections_abc'].append(str(py_file.relative_to('/workspace')))
            results['total_collections_abc_imports'] += len(patterns['from_collections_abc'].findall(content))

        if patterns['from_shim'].search(content) or patterns['import_shim'].search(content):
            results['files_with_shim'].append(str(py_file.relative_to('/workspace')))
            results['total_shim_imports'] += len(patterns['from_shim'].findall(content)) + len(patterns['import_shim'].findall(content))
    except Exception as e:
        pass

print("=== Collections ABC Import Analysis ===\n")
print(f"Files using collections.abc: {len(results['files_with_collections_abc'])}")
print(f"Total collections.abc imports: {results['total_collections_abc_imports']}\n")
print(f"Files using shim: {len(results['files_with_shim'])}")
print(f"Total shim imports: {results['total_shim_imports']}\n")

if results['files_with_shim']:
    print("Files still using the shim:")
    for f in sorted(results['files_with_shim']):
        print(f"  - {f}")
else:
    print("✓ No files are directly importing from the shim!")

print("\nSample files using proper collections.abc:")
for f in sorted(results['files_with_collections_abc'])[:5]:
    print(f"  - {f}")
EOF
