#!/usr/bin/env python3
"""Check for edge cases in imports."""
import re
from pathlib import Path

workspace = Path('/workspace')
lib_path = workspace / 'lib' / 'ansible'

patterns = {
    'dynamic_import': re.compile(r'__import__\(.*_collections_compat'),
    'getattr_import': re.compile(r'getattr\(.*_collections_compat'),
    'importlib_import': re.compile(r'importlib\.import_module\(.*_collections_compat'),
    'exec_import': re.compile(r'exec\(.*_collections_compat'),
    'eval_import': re.compile(r'eval\(.*_collections_compat'),
}

print("=== EDGE CASE CHECKS ===\n")

found_issues = False

for py_file in lib_path.rglob('*.py'):
    try:
        content = py_file.read_text(encoding='utf-8')
        rel_path = py_file.relative_to(workspace)

        for pattern_name, pattern in patterns.items():
            if pattern.search(content):
                print(f"✗ {rel_path}: Potential {pattern_name}")
                found_issues = True
    except Exception as e:
        pass

if not found_issues:
    print("✓ No dynamic import patterns found")

# Check for wildcard imports from module_utils.common
print("\n=== CHECKING FOR WILDCARD IMPORTS ===\n")

wildcard_pattern = re.compile(r'from\s+ansible\.module_utils\.common\s+import\s+\*')

for py_file in lib_path.rglob('*.py'):
    try:
        content = py_file.read_text(encoding='utf-8')
        rel_path = py_file.relative_to(workspace)

        if wildcard_pattern.search(content):
            print(f"! {rel_path}: Uses wildcard import from module_utils.common")
    except Exception as e:
        pass

print("\n✓ No issues found")
EOF
